import { Vex, Guardrail } from '@vex_dev/sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY! });

const retrievalGuardrail = new Guardrail({
  name: 'rag_retrieval_validation',
  checks: [
    'source_faithfulness',
    { context_relevance: { threshold: 0.7 } },
    'structured_output_schema'
  ]
});

const validatedRetrieval = await vex.runGuardrail(
  retrievalGuardrail,
  {
    query: userQuery,
    retrieved_chunks: rawResults,
    scores: rawResults.map(r => r.score)
  }
);

if (!validatedRetrieval.passes) {
  throw new Error(`Retrieval failed validation: ${validatedRetrieval.issues}`);
}

const freshnessGuardrail = new Guardrail({
  name: 'context_freshness',
  checks: [
    'temporal_freshness',
    { staleness_check: { max_age_hours: 24 } },
    'memory_consistency'
  ]
});

const contextCheck = await vex.runGuardrail(freshnessGuardrail, {
  retrieved_context: assembledContext,
  memory_context: conversationHistory,
  current_timestamp: Date.now(),
  knowledge_base_version: kbVersion
});

if (contextCheck.issues.stale_sources?.length > 0) {
  // Re-retrieve affected sources
  console.warn('Stale context detected:', contextCheck.issues.stale_sources);
}

const generationGuardrail = new Guardrail({
  name: 'rag_final_verification',
  checks: [
    'hallucination_detection',
    'citation_accuracy',
    { source_faithfulness: { strict: true } },
    'grounding_score'
  ]
});

const finalVerification = await vex.runGuardrail(generationGuardrail, {
  generated_answer: llmResponse.text,
  source_context: assembledContext.context,
  extracted_citations: citations,
  source_mapping: enrichedInput.sources
});

if (finalVerification.score < 0.85) {
  return { error: 'Response failed quality checks', issues: finalVerification.issues };
}

return {
  ...finalAnswer,
  vex_score: finalVerification.score,
  verified: true
};
